  ('aboriginal-64311456-moex-00247', 'aboriginal-64311456', 'aboriginal-64311456-moex-111-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '關於公務人員任用之規定，下列敘述何者正確？', '["行政機關初任甲為機要人員，依然要有符合依法考試及格之規定", "乙為薦任六職等之公務員，得先權理薦任八職等之職務", "職等標準及職務列等表，均授權銓敘部自行定之，後報考試院備查", "丙為高考二級通過，取得薦任七職等之任用資格，經訓練之後，即可分發實授"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "86c821c6be4c", "answer_pdf_sha1": "b3a415d6eb0d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "603", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
