  ('aboriginal-64311456-moex-00250', 'aboriginal-64311456', 'aboriginal-64311456-moex-111-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '關於公營事業機構與公營造物之敘述，下列何者錯誤？', '["公營事業機構通常採公司之組織型態", "公營事業機構之行為原則上屬私經濟範疇", "公營造物與利用人間之法律關係稱為營造物利用關係", "營造物利用關係限於私經濟性質"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "86c821c6be4c", "answer_pdf_sha1": "b3a415d6eb0d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "603", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
